--
-- Name: create_user_quota(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_user_quota() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
    BEGIN
            user_id,
            tier,
            monthly_scan_limit,
            max_files_per_scan,
            scan_priority,
            webhooks_enabled,
            api_access_enabled,
            result_retention_days
        ) VALUES (
            NEW.id,
            NEW.tier,
            CASE NEW.tier
                WHEN 'free' THEN 10
                WHEN 'pro' THEN -1  -- -1 means unlimited
                WHEN 'enterprise' THEN -1
                WHEN 'enterprise_broker' THEN -1
                ELSE 10
            END,
            CASE NEW.tier
                WHEN 'free' THEN 25
                WHEN 'pro' THEN 100
                WHEN 'enterprise' THEN -1  -- unlimited
                WHEN 'enterprise_broker' THEN -1
                ELSE 25
            END,
            CASE NEW.tier
                WHEN 'free' THEN 25
                WHEN 'pro' THEN 50
                WHEN 'enterprise' THEN 75
                WHEN 'enterprise_broker' THEN 100
                ELSE 25
            END,
            CASE NEW.tier
                WHEN 'free' THEN FALSE
                ELSE TRUE
            END,
            CASE NEW.tier
                WHEN 'free' THEN FALSE
                ELSE TRUE
            END,
            CASE NEW.tier
                WHEN 'free' THEN 30
                WHEN 'pro' THEN 365
                WHEN 'enterprise' THEN 730
                WHEN 'enterprise_broker' THEN 730
                ELSE 30
            END
        );
        RETURN NEW;
    END;
    $$;


ALTER FUNCTION public.create_user_quota() OWNER TO postgres;

