3150cfa5-32c9-4d4b-b7ce-9b31d611d117	b682867e-e716-4e83-a8c5-24b78bb462cf	Front Running	\N	ethereum	// SPDX-License-Identifier: MIT\npragma solidity ^0.8.0;\n\n/**\n * @title Front-Running Vulnerability Example\n * @dev VULNERABLE - DO NOT USE IN PRODUCTION\n *\n * This contract is vulnerable to front-running attacks where attackers\n * can see pending transactions and submit their own with higher gas fees.\n */\ncontract VulnerablePuzzle {\n    bytes32 public solutionHash;\n    uint256 public reward = 10 ether;\n    address public owner;\n    bool public solved;\n\n    constructor(bytes32 _solutionHash) payable {\n        solutionHash = _solutionHash;\n        owner = msg.sender;\n    }\n\n    // VULNERABLE: Solution is visible in mempool before confirmation\n    function submitSolution(string memory _solution) public {\n        require(!solved, "Already solved");\n\n        // VULNERABILITY: Anyone can see the solution in the mempool and front-run it\n        require(keccak256(abi.encodePacked(_solution)) == solutionHash, "Incorrect solution");\n\n        solved = true;\n        payable(msg.sender).transfer(reward);\n    }\n\n    receive() external payable {}\n}\n\n/**\n * @title Front-Running in DEX\n * @dev Shows front-running vulnerability in token swaps\n */\ncontract VulnerableDEX {\n    mapping(address => uint256) public tokenABalance;\n    mapping(address => uint256) public tokenBBalance;\n    uint256 public tokenAReserve = 1000 ether;\n    uint256 public tokenBReserve = 1000 ether;\n\n    // Simplified constant product AMM\n    function getSwapAmount(uint256 _tokenAAmount) public view returns (uint256) {\n        // x * y = k\n        uint256 k = tokenAReserve * tokenBReserve;\n        uint256 newTokenAReserve = tokenAReserve + _tokenAAmount;\n        uint256 newTokenBReserve = k / newTokenAReserve;\n        return tokenBReserve - newTokenBReserve;\n    }\n\n    // VULNERABLE: Transaction ordering dependency\n    function swapAforB(uint256 _tokenAAmount, uint256 _minTokenBAmount) public {\n        uint256 tokenBAmount = getSwapAmount(_tokenAAmount);\n\n        // VULNERABILITY: Front-runner can see this transaction and swap before it,\n        // causing the price to move and potentially causing this transaction to fail\n        // or execute at a worse rate\n        require(tokenBAmount >= _minTokenBAmount, "Slippage too high");\n\n        tokenABalance[msg.sender] -= _tokenAAmount;\n        tokenBBalance[msg.sender] += tokenBAmount;\n\n        tokenAReserve += _tokenAAmount;\n        tokenBReserve -= tokenBAmount;\n    }\n\n    function deposit(uint256 _tokenA, uint256 _tokenB) public {\n        tokenABalance[msg.sender] += _tokenA;\n        tokenBBalance[msg.sender] += _tokenB;\n    }\n}\n\n/**\n * @title Transaction Ordering Dependence\n * @dev Shows vulnerability where transaction order affects outcome\n */\ncontract VulnerableICO {\n    uint256 public price = 1 ether;\n    uint256 public tokensAvailable = 1000;\n    mapping(address => uint256) public balances;\n    address public owner;\n\n    constructor() {\n        owner = msg.sender;\n    }\n\n    // VULNERABLE: Price can be front-run\n    function updatePrice(uint256 _newPrice) public {\n        require(msg.sender == owner, "Not owner");\n        // VULNERABILITY: Users buying tokens can be front-run by owner increasing price\n        price = _newPrice;\n    }\n\n    function buyTokens(uint256 _amount) public payable {\n        require(tokensAvailable >= _amount, "Not enough tokens");\n        // VULNERABILITY: Price might change between when user submits transaction\n        // and when it's mined\n        require(msg.value >= price * _amount, "Insufficient payment");\n\n        tokensAvailable -= _amount;\n        balances[msg.sender] += _amount;\n    }\n}\n\n/**\n * @title ERC20 Approval Front-Running\n * @dev Shows approve/transferFrom race condition\n */\ncontract VulnerableERC20 {\n    mapping(address => uint256) public balances;\n    mapping(address => mapping(address => uint256)) public allowances;\n\n    string public name = "Vulnerable Token";\n    string public symbol = "VULN";\n\n    constructor(uint256 _initialSupply) {\n        balances[msg.sender] = _initialSupply;\n    }\n\n    // VULNERABLE: Changing allowance can be front-run\n    function approve(address _spender, uint256 _amount) public returns (bool) {\n        // VULNERABILITY: If user tries to change allowance from N to M,\n        // spender can front-run by:\n        // 1. transferFrom N tokens (old allowance)\n        // 2. Let approve transaction execute\n        // 3. transferFrom M tokens (new allowance)\n        // Result: spender transferred N+M tokens instead of M\n        allowances[msg.sender][_spender] = _amount;\n        return true;\n    }\n\n    function transferFrom(address _from, address _to, uint256 _amount) public returns (bool) {\n        require(balances[_from] >= _amount, "Insufficient balance");\n        require(allowances[_from][msg.sender] >= _amount, "Insufficient allowance");\n\n        balances[_from] -= _amount;\n        balances[_to] += _amount;\n        allowances[_from][msg.sender] -= _amount;\n\n        return true;\n    }\n}\n	\N	146	f	\N	1	0	solidity	0.8.0	{"license": "MIT", "detection_method": "extension", "detection_confidence": 0.95}	scanned	2025-11-06 00:39:57.853642+00	2025-11-08 15:59:51.307379+00	plain	\N
e8efabc4-bcc8-4d05-a11d-4bff8add0f8d	b6c269e7-721b-4a01-928b-72a687d8ad1c	AAVE-LendingPool-simplified.sol	\N	ethereum	// SPDX-License-Identifier: MIT\npragma solidity ^0.8.0;\n\n/**\n * @title Simplified Aave V2 LendingPool\n * @notice Representative implementation based on Aave V2 patterns\n * @dev Simplified for FP testing - focuses on core patterns\n */\n\ninterface ILendingPoolAddressesProvider {\n    function getPriceOracle() external view returns (address);\n}\n\ninterface IPriceOracle {\n    function getAssetPrice(address asset) external view returns (uint256);\n}\n\ninterface IAToken {\n    function mint(address user, uint256 amount, uint256 index) external returns (bool);\n    function burn(address user, address receiverOfUnderlying, uint256 amount, uint256 index) external;\n}\n\ncontract LendingPool {\n    ILendingPoolAddressesProvider public addressesProvider;\n\n    mapping(address => ReserveData) internal reserves;\n    mapping(address => UserConfiguration) internal usersConfig;\n\n    struct ReserveData {\n        uint256 liquidityIndex;\n        uint256 variableBorrowIndex;\n        uint128 currentLiquidityRate;\n        uint128 currentVariableBorrowRate;\n        address aTokenAddress;\n        address variableDebtTokenAddress;\n    }\n\n    struct UserConfiguration {\n        uint256 data;\n    }\n\n    enum InterestRateMode { NONE, STABLE, VARIABLE }\n\n    // Core Aave V2 functions - should be detected by is_aave_lending_pool()\n\n    function deposit(\n        address asset,\n        uint256 amount,\n        address onBehalfOf,\n        uint16 referralCode\n    ) external {\n        ReserveData storage reserve = reserves[asset];\n\n        // Transfer asset from user\n        // Update liquidity index\n        // Mint aTokens\n        IAToken(reserve.aTokenAddress).mint(onBehalfOf, amount, reserve.liquidityIndex);\n    }\n\n    function withdraw(\n        address asset,\n        uint256 amount,\n        address to\n    ) external returns (uint256) {\n        ReserveData storage reserve = reserves[asset];\n\n        // Burn aTokens\n        IAToken(reserve.aTokenAddress).burn(msg.sender, to, amount, reserve.liquidityIndex);\n\n        // Transfer underlying to user\n        return amount;\n    }\n\n    function borrow(\n        address asset,\n        uint256 amount,\n        uint256 interestRateMode,\n        uint16 referralCode,\n        address onBehalfOf\n    ) external {\n        // Validate borrow (check collateral via getAccountData)\n        (uint256 totalCollateralETH, uint256 totalDebtETH, , , ,uint256 healthFactor) = getUserAccountData(onBehalfOf);\n\n        require(healthFactor > 1e18, "Health factor too low");\n\n        // Transfer borrowed asset to user\n        // Update debt\n    }\n\n    function repay(\n        address asset,\n        uint256 amount,\n        uint256 rateMode,\n        address onBehalfOf\n    ) external returns (uint256) {\n        // Transfer repayment from user\n        // Update debt\n        return amount;\n    }\n\n    // Flash loan function - provider pattern\n    function flashLoan(\n        address receiverAddress,\n        address[] calldata assets,\n        uint256[] calldata amounts,\n        uint256[] calldata modes,\n        address onBehalfOf,\n        bytes calldata params,\n        uint16 referralCode\n    ) external {\n        // Flash loan implementation\n        // Calls executeOperation on receiver\n        // Verifies repayment + premium\n    }\n\n    // Liquidation function\n    function liquidationCall(\n        address collateralAsset,\n        address debtAsset,\n        address user,\n        uint256 debtToCover,\n        bool receiveAToken\n    ) external {\n        // Liquidation logic\n        (uint256 totalCollateralETH, uint256 totalDebtETH, , , , uint256 healthFactor) = getUserAccountData(user);\n\n        require(healthFactor < 1e18, "Health factor OK");\n\n        // Calculate liquidation amounts\n        // Seize collateral\n        // Repay debt\n    }\n\n    // User account data - uses oracle for pricing\n    function getUserAccountData(address user)\n        public\n        view\n        returns (\n            uint256 totalCollateralETH,\n            uint256 totalDebtETH,\n            uint256 availableBorrowsETH,\n            uint256 currentLiquidationThreshold,\n            uint256 ltv,\n            uint256 healthFactor\n        )\n    {\n        // Calculate total collateral and debt in ETH\n        // Uses price oracle\n        IPriceOracle oracle = IPriceOracle(addressesProvider.getPriceOracle());\n\n        // This is legitimate oracle usage - not a vulnerability\n        // Aave uses Chainlink oracles with staleness checks\n\n        // Simplified calculation\n        totalCollateralETH = 1000e18;\n        totalDebtETH = 500e18;\n        healthFactor = totalCollateralETH * 1e18 / totalDebtETH;\n\n        return (totalCollateralETH, totalDebtETH, availableBorrowsETH, currentLiquidationThreshold, ltv, healthFactor);\n    }\n\n    function getReserveData(address asset) external view returns (ReserveData memory) {\n        return reserves[asset];\n    }\n}\n	\N	165	f	\N	1	0	solidity	0.8.0	{"license": "MIT", "detection_method": "extension", "detection_confidence": 0.95}	scanning	2025-11-22 05:46:07.985623+00	2025-11-28 22:30:36.528616+00	plain	\N
570c9ac3-85d8-438d-8a1d-2785b89ee152	b6c269e7-721b-4a01-928b-72a687d8ad1c	UniswapV2Pair-simplified.sol	\N	ethereum	// SPDX-License-Identifier: MIT\npragma solidity ^0.8.0;\n\n/**\n * @title Simplified Uniswap V2 Pair\n * @notice Representative implementation based on Uniswap V2 patterns\n * @dev Simplified for FP testing - focuses on core AMM patterns\n */\n\ninterface IERC20 {\n    function transfer(address to, uint256 value) external returns (bool);\n    function transferFrom(address from, address to, uint256 value) external returns (bool);\n    function balanceOf(address owner) external view returns (uint256);\n}\n\ncontract UniswapV2Pair {\n    string public constant name = 'Uniswap V2';\n    string public constant symbol = 'UNI-V2';\n    uint8 public constant decimals = 18;\n\n    uint256 public totalSupply;\n    mapping(address => uint256) public balanceOf;\n\n    address public factory;\n    address public token0;\n    address public token1;\n\n    uint112 private reserve0;\n    uint112 private reserve1;\n    uint32 private blockTimestampLast;\n\n    // TWAP oracles - Uniswap V2 IS the oracle source\n    uint256 public price0CumulativeLast;\n    uint256 public price1CumulativeLast;\n\n    uint256 private unlocked = 1;\n\n    modifier lock() {\n        require(unlocked == 1, 'UniswapV2: LOCKED');\n        unlocked = 0;\n        _;\n        unlocked = 1;\n    }\n\n    // Core AMM functions - should be detected by is_uniswap_v2_pair()\n\n    function getReserves() public view returns (uint112 _reserve0, uint112 _reserve1, uint32 _blockTimestampLast) {\n        _reserve0 = reserve0;\n        _reserve1 = reserve1;\n        _blockTimestampLast = blockTimestampLast;\n    }\n\n    function mint(address to) external lock returns (uint256 liquidity) {\n        (uint112 _reserve0, uint112 _reserve1,) = getReserves();\n        uint256 balance0 = IERC20(token0).balanceOf(address(this));\n        uint256 balance1 = IERC20(token1).balanceOf(address(this));\n        uint256 amount0 = balance0 - _reserve0;\n        uint256 amount1 = balance1 - _reserve1;\n\n        if (totalSupply == 0) {\n            liquidity = sqrt(amount0 * amount1);\n        } else {\n            liquidity = min(amount0 * totalSupply / _reserve0, amount1 * totalSupply / _reserve1);\n        }\n\n        require(liquidity > 0, 'UniswapV2: INSUFFICIENT_LIQUIDITY_MINTED');\n        balanceOf[to] += liquidity;\n        totalSupply += liquidity;\n\n        _update(balance0, balance1, _reserve0, _reserve1);\n    }\n\n    function burn(address to) external lock returns (uint256 amount0, uint256 amount1) {\n        uint256 balance0 = IERC20(token0).balanceOf(address(this));\n        uint256 balance1 = IERC20(token1).balanceOf(address(this));\n        uint256 liquidity = balanceOf[address(this)];\n\n        amount0 = liquidity * balance0 / totalSupply;\n        amount1 = liquidity * balance1 / totalSupply;\n\n        require(amount0 > 0 && amount1 > 0, 'UniswapV2: INSUFFICIENT_LIQUIDITY_BURNED');\n\n        balanceOf[address(this)] -= liquidity;\n        totalSupply -= liquidity;\n\n        IERC20(token0).transfer(to, amount0);\n        IERC20(token1).transfer(to, amount1);\n\n        balance0 = IERC20(token0).balanceOf(address(this));\n        balance1 = IERC20(token1).balanceOf(address(this));\n\n        _update(balance0, balance1, reserve0, reserve1);\n    }\n\n    // Swap function - legitimate MEV target\n    function swap(uint256 amount0Out, uint256 amount1Out, address to, bytes calldata data) external lock {\n        require(amount0Out > 0 || amount1Out > 0, 'UniswapV2: INSUFFICIENT_OUTPUT_AMOUNT');\n        (uint112 _reserve0, uint112 _reserve1,) = getReserves();\n        require(amount0Out < _reserve0 && amount1Out < _reserve1, 'UniswapV2: INSUFFICIENT_LIQUIDITY');\n\n        uint256 balance0;\n        uint256 balance1;\n\n        if (amount0Out > 0) IERC20(token0).transfer(to, amount0Out);\n        if (amount1Out > 0) IERC20(token1).transfer(to, amount1Out);\n\n        // Flash swap callback\n        if (data.length > 0) {\n            // This is a flash swap - legitimate pattern\n            // Should NOT trigger flash loan vulnerabilities\n        }\n\n        balance0 = IERC20(token0).balanceOf(address(this));\n        balance1 = IERC20(token1).balanceOf(address(this));\n\n        uint256 amount0In = balance0 > _reserve0 - amount0Out ? balance0 - (_reserve0 - amount0Out) : 0;\n        uint256 amount1In = balance1 > _reserve1 - amount1Out ? balance1 - (_reserve1 - amount1Out) : 0;\n\n        require(amount0In > 0 || amount1In > 0, 'UniswapV2: INSUFFICIENT_INPUT_AMOUNT');\n\n        // Constant product formula check\n        uint256 balance0Adjusted = balance0 * 1000 - amount0In * 3;\n        uint256 balance1Adjusted = balance1 * 1000 - amount1In * 3;\n        require(balance0Adjusted * balance1Adjusted >= uint256(_reserve0) * _reserve1 * 1000000, 'UniswapV2: K');\n\n        _update(balance0, balance1, _reserve0, _reserve1);\n    }\n\n    // TWAP oracle update - this pool IS the oracle\n    function _update(uint256 balance0, uint256 balance1, uint112 _reserve0, uint112 _reserve1) private {\n        require(balance0 <= type(uint112).max && balance1 <= type(uint112).max, 'UniswapV2: OVERFLOW');\n        uint32 blockTimestamp = uint32(block.timestamp % 2**32);\n        uint32 timeElapsed = blockTimestamp - blockTimestampLast;\n\n        if (timeElapsed > 0 && _reserve0 != 0 && _reserve1 != 0) {\n            // Update cumulative prices for TWAP oracle\n            price0CumulativeLast += uint256(_reserve1 / _reserve0) * timeElapsed;\n            price1CumulativeLast += uint256(_reserve0 / _reserve1) * timeElapsed;\n        }\n\n        reserve0 = uint112(balance0);\n        reserve1 = uint112(balance1);\n        blockTimestampLast = blockTimestamp;\n    }\n\n    function sqrt(uint256 y) internal pure returns (uint256 z) {\n        if (y > 3) {\n            z = y;\n            uint256 x = y / 2 + 1;\n            while (x < z) {\n                z = x;\n                x = (y / x + x) / 2;\n            }\n        } else if (y != 0) {\n            z = 1;\n        }\n    }\n\n    function min(uint256 x, uint256 y) internal pure returns (uint256 z) {\n        z = x < y ? x : y;\n    }\n}\n	\N	162	f	\N	1	0	solidity	0.8.0	{"license": "MIT", "detection_method": "extension", "detection_confidence": 0.95}	scanned	2025-11-21 00:24:04.211269+00	2025-11-21 16:33:36.668101+00	plain	\N
