BVD-SOLANA-SEC-001	Malicious Transaction Simulation	Programs that simulate transactions or perform operations based on simulated results without proper validation. Transaction simulation in Solana is meant for testing and pre-flight checks, not for making security decisions. Programs that rely on simulation results can be manipulated by attackers who provide fake simulation data or manipulate simulation parameters.	security	high	\N	\N	A03:2021	{"description": "Never use simulation results for security decisions or authorization checks. Simulations should only be used off-chain for UI/UX purposes. All security checks must be performed on-chain during actual transaction execution.", "code_example": "// VULNERABLE: Using simulation for authorization\\nuse solana_client::rpc_client::RpcClient;\\nuse solana_sdk::transaction::Transaction;\\n\\npub fn authorize_transaction(\\n    client: &RpcClient,\\n    transaction: &Transaction,\\n) -> Result<bool, Box<dyn std::error::Error>> {\\n    // Simulating transaction to check if it would succeed\\n    let simulation = client.simulate_transaction(transaction)?;\\n    \\n    // DANGEROUS: Making security decision based on simulation!\\n    if simulation.value.err.is_none() {\\n        // Attacker can manipulate simulation results\\n        return Ok(true);\\n    }\\n    Ok(false)\\n}\\n\\n// VULNERABLE: Accepting simulated account data\\npub fn process_with_simulation(\\n    account_data: &[u8],\\n    is_simulated: bool,\\n) -> ProgramResult {\\n    if is_simulated {\\n        // Skip validation for simulated data - DANGEROUS!\\n        return process_account(account_data);\\n    }\\n    \\n    // Only validate real transactions\\n    validate_account(account_data)?;\\n    process_account(account_data)\\n}\\n\\n// SECURE: Simulation only for UI/estimates\\nuse solana_client::rpc_client::RpcClient;\\nuse solana_sdk::transaction::Transaction;\\n\\n// Off-chain code for UI\\npub async fn estimate_transaction_cost(\\n    client: &RpcClient,\\n    transaction: &Transaction,\\n) -> Result<u64, Box<dyn std::error::Error>> {\\n    // Simulation is OK for estimates, not authorization\\n    let simulation = client.simulate_transaction(transaction)?;\\n    \\n    // Use simulation only for displaying estimate to user\\n    let cost = simulation.value.units_consumed.unwrap_or(0);\\n    Ok(cost)\\n}\\n\\n// On-chain code - never check if simulated\\npub fn process_instruction(\\n    program_id: &Pubkey,\\n    accounts: &[AccountInfo],\\n    instruction_data: &[u8],\\n) -> ProgramResult {\\n    // ALWAYS validate, regardless of simulation\\n    validate_accounts(accounts)?;\\n    validate_instruction_data(instruction_data)?;\\n    \\n    // All security checks performed on-chain\\n    let account = &accounts[0];\\n    if !account.is_signer {\\n        return Err(ProgramError::MissingRequiredSignature);\\n    }\\n    \\n    if account.owner != program_id {\\n        return Err(ProgramError::IncorrectProgramId);\\n    }\\n    \\n    // Process with full validation\\n    process_validated_instruction(accounts, instruction_data)\\n}\\n\\n// SECURE: Using Anchor (no simulation bypass)\\nuse anchor_lang::prelude::*;\\n\\n#[program]\\npub mod my_program {\\n    use super::*;\\n    \\n    pub fn process_transaction(\\n        ctx: Context<ProcessTransaction>,\\n        amount: u64,\\n    ) -> Result<()> {\\n        // Anchor ALWAYS validates:\\n        // - Account discriminators\\n        // - Account ownership\\n        // - Signer requirements\\n        // - Custom constraints\\n        // \\n        // No way to bypass via simulation\\n        \\n        let account = &mut ctx.accounts.user_account;\\n        \\n        // All checks performed on-chain\\n        require!(\\n            account.balance >= amount,\\n            ErrorCode::InsufficientFunds\\n        );\\n        \\n        account.balance = account.balance\\n            .checked_sub(amount)\\n            .ok_or(ErrorCode::ArithmeticOverflow)?;\\n        \\n        Ok(())\\n    }\\n}\\n\\n#[derive(Accounts)]\\npub struct ProcessTransaction<'info> {\\n    #[account(\\n        mut,\\n        has_one = authority,  // Validated on-chain\\n    )]\\n    pub user_account: Account<'info, UserAccount>,\\n    pub authority: Signer<'info>,  // Must be signer on-chain\\n}\\n\\n#[account]\\npub struct UserAccount {\\n    pub authority: Pubkey,\\n    pub balance: u64,\\n}\\n\\n#[error_code]\\npub enum ErrorCode {\\n    #[msg(\\"Insufficient funds\\")]\\n    InsufficientFunds,\\n    #[msg(\\"Arithmetic overflow\\")]\\n    ArithmeticOverflow,\\n}"}	[]	["https://docs.solana.com/api/http#simulatetransaction", "https://docs.solana.com/developing/clients/jsonrpc-api#simulatetransaction"]	{}	0	{}	\N	{}	2025-11-08 17:33:25.926397+00	2025-11-29 01:51:09.919077+00	t
BVD-VYPER-GAS-012	High Cyclomatic Complexity in Vyper	Function has excessive branching and complexity making it expensive and hard to audit	gas-optimization	informational	SWC-128	CWE-1121	A8: Software and Data Integrity Failures	Refactor complex functions into smaller, focused functions	[{"language": "vyper", "fixed_code": "@external\\ndef complex_logic(a: uint256, b: uint256, c: uint256) -> uint256:\\n    return self._calculate(a, b, c)\\n\\n@internal\\ndef _calculate(a: uint256, b: uint256, c: uint256) -> uint256:\\n    if a <= 10:\\n        return 0\\n    return self._calculate_high_a(a, b, c)\\n\\n@internal\\ndef _calculate_high_a(a: uint256, b: uint256, c: uint256) -> uint256:\\n    if b > 20 and c > 30:\\n        return a + b + c\\n    elif b > 20:\\n        return a + b\\n    elif c > 30:\\n        return a + c\\n    else:\\n        return a", "vulnerable_code": "@external\\ndef complex_logic(a: uint256, b: uint256, c: uint256) -> uint256:\\n    result: uint256 = 0\\n    if a > 10:\\n        if b > 20:\\n            if c > 30:\\n                result = a + b + c\\n            else:\\n                result = a + b\\n        else:\\n            if c > 30:\\n                result = a + c\\n            else:\\n                result = a\\n    else:\\n        # Many more nested conditions...\\n        result = 0\\n    return result"}]	["https://docs.vyperlang.org/"]	{static-analysis}	0.25	{vyper}	Function with high cyclomatic complexity in Vyper	{vyper,complexity,refactor,maintainability}	2025-11-08 17:32:16.271675+00	2025-11-29 01:51:09.592211+00	t
BVD-SOLANA-CPI-001	Arbitrary Cross-Program Invocation	Unrestricted cross-program invocations (CPI) where programs accept arbitrary program IDs without validation. In Solana, CPI allows programs to call other programs, but without proper validation, malicious programs can be invoked instead of legitimate ones. This can lead to unauthorized state changes, fund theft, or complete program compromise.	cross-program-invocation	critical	\N	\N	A03:2021	{"description": "Always validate that CPI target program IDs match expected addresses. Use hardcoded program IDs or verify against known addresses before invoking.", "code_example": "// VULNERABLE: Arbitrary CPI target\\nuse solana_program::program::invoke;\\n\\npub fn process(\\n    accounts: &[AccountInfo],\\n) -> ProgramResult {\\n    let target_program = &accounts[0];\\n    \\n    // No validation - can call ANY program!\\n    invoke(\\n        &instruction,\\n        &[target_program.clone()],\\n    )?;\\n    Ok(())\\n}\\n\\n// SECURE: Validate CPI target\\nuse solana_program::program::invoke;\\nuse spl_token::id as token_program_id;\\n\\npub fn process(\\n    accounts: &[AccountInfo],\\n) -> ProgramResult {\\n    let target_program = &accounts[0];\\n    \\n    // Validate program ID before CPI\\n    if target_program.key != &token_program_id() {\\n        return Err(ProgramError::IncorrectProgramId);\\n    }\\n    \\n    invoke(\\n        &instruction,\\n        &[target_program.clone()],\\n    )?;\\n    Ok(())\\n}\\n\\n// SECURE: Using Anchor with explicit program constraint\\nuse anchor_lang::prelude::*;\\nuse anchor_spl::token::{Token, TokenAccount};\\n\\n#[derive(Accounts)]\\npub struct TransferTokens<'info> {\\n    #[account(mut)]\\n    pub from: Account<'info, TokenAccount>,\\n    #[account(mut)]\\n    pub to: Account<'info, TokenAccount>,\\n    pub authority: Signer<'info>,\\n    // Anchor validates this is the SPL Token program\\n    pub token_program: Program<'info, Token>,\\n}\\n\\npub fn transfer_tokens(ctx: Context<TransferTokens>, amount: u64) -> Result<()> {\\n    // CPI target is guaranteed to be SPL Token program\\n    token::transfer(\\n        CpiContext::new(\\n            ctx.accounts.token_program.to_account_info(),\\n            Transfer {\\n                from: ctx.accounts.from.to_account_info(),\\n                to: ctx.accounts.to.to_account_info(),\\n                authority: ctx.accounts.authority.to_account_info(),\\n            },\\n        ),\\n        amount,\\n    )?;\\n    Ok(())\\n}"}	[]	["https://github.com/coral-xyz/sealevel-attacks/tree/master/programs/8-arbitrary-cpi", "https://docs.solana.com/developing/programming-model/calling-between-programs"]	{}	0	{}	\N	{}	2025-11-08 17:33:25.867742+00	2025-11-29 01:51:09.835351+00	t
BVD-SOLIDITY-EMERGENCY-001	Emergency Function Abuse	Emergency function vulnerabilities including missing access controls, pause centralization, withdrawal abuse, and excessive emergency powers	access-control	medium	SWC-XXX	CWE-284	A1: Access Control	Implement proper access controls on emergency functions, use multi-sig for emergency operations, add timelock delays, and limit emergency function scope	["Require multi-sig for emergency pause", "Add timelock even for emergency functions", "Limit emergency withdrawal amounts", "Implement cool-down periods between emergency uses"]	["https://docs.openzeppelin.com/contracts/4.x/api/security#Pausable"]	{static,manual}	0.25	{solidity}	Emergency functions with insufficient access controls or excessive privileges	{emergency,pause,withdrawal,"access control"}	2025-11-29 01:17:01.498746+00	2025-11-29 01:51:10.372328+00	t
BVD-SOLANA-ACC-004	Missing Owner Check	Operations lacking ownership verification where programs fail to validate that accounts are owned by the expected program. In Solana's security model, programs can only modify accounts they own. Missing owner checks allow malicious programs to pass fake accounts that will be accepted and processed, potentially leading to unauthorized state changes or fund theft.	account-validation	critical	\N	\N	A01:2021	{"description": "Always validate account ownership before processing. Use Anchor's Account types which automatically validate ownership, or manually check the owner field.", "code_example": "// VULNERABLE: No owner check\\npub fn process_instruction(\\n    program_id: &Pubkey,\\n    accounts: &[AccountInfo],\\n) -> ProgramResult {\\n    let account = &accounts[0];\\n    // Process account without checking owner\\n    Ok(())\\n}\\n\\n// SECURE: Validate account owner\\npub fn process_instruction(\\n    program_id: &Pubkey,\\n    accounts: &[AccountInfo],\\n) -> ProgramResult {\\n    let account = &accounts[0];\\n    \\n    // Check that account is owned by this program\\n    if account.owner != program_id {\\n        return Err(ProgramError::IncorrectProgramId);\\n    }\\n    \\n    // Or check for specific program (e.g., Token Program)\\n    if account.owner != &spl_token::id() {\\n        return Err(ProgramError::InvalidAccountOwner);\\n    }\\n    \\n    Ok(())\\n}\\n\\n// SECURE: Using Anchor (automatic owner check)\\nuse anchor_lang::prelude::*;\\n\\n#[derive(Accounts)]\\npub struct ProcessAccounts<'info> {\\n    // Anchor validates that account is owned by the current program\\n    #[account(mut)]\\n    pub my_account: Account<'info, MyAccount>,\\n}"}	[]	["https://github.com/coral-xyz/sealevel-attacks/tree/master/programs/3-owner-checks", "https://docs.solana.com/developing/programming-model/accounts#ownership"]	{}	0	{}	\N	{}	2025-11-08 17:33:25.817874+00	2025-11-29 01:51:09.80422+00	t
